import urllib.request, json
urls=[
 'https://www.rcsb.org/fasta/entry/2IB5/download',
 'https://www.ebi.ac.uk/pdbe/api/pdb/entry/summary/2IB5',
 'https://fpbase.org/api/4.0/proteins/?format=json',
]
for url in urls:
    try:
        req=urllib.request.Request(url, headers={'User-Agent':'Mozilla/5.0'})
        with urllib.request.urlopen(req, timeout=8) as r:
            data=r.read(500)
            print('\\nURL', url)
            print('status', r.status, 'len-prefix', len(data))
            print(data[:200])
    except Exception as e:
        print('\\nURL', url)
        print(type(e).__name__, e)
